/**
 * Custom theme system for T3 Code.
 *
 * Defines the ThemeId union, the ThemeColors shape, and the three built-in
 * themes. This module is pure TypeScript — no Effect/Schema runtime required.
 */

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export const THEME_IDS: readonly ThemeId[] = ["t3-dark", "t3-light", "t3-midnight"] as const;

/**
