/**
 * ThemeSelector — visual picker for the T3 Code named theme system.
 *
 * Renders each built-in theme as a clickable card with three inline color
 * swatches (background / sidebar / primary accent) so users can preview the
 * palette before selecting. The active theme is indicated by a highlighted
 * border and an "Active" badge.
 */

import { useAppTheme } from "~/providers/ThemeProvider";
import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import type { ThemeId } from "@t3tools/shared/theme";

// ─────────────────────────────────────────────────────────────────────────────
// Swatch strip
// ─────────────────────────────────────────────────────────────────────────────

function ThemeSwatches({ themeId }: { themeId: ThemeId }) {
  const { background, sidebar, primary, border, isDark } = BUILT_IN_THEMES[themeId].colors;
  return (
    <div
      className="flex h-9 w-16 shrink-0 overflow-hidden rounded-md"
      style={{
        border: `1px solid ${isDark ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.10)"}`,
      }}
      aria-hidden="true"
    >
      {/* Background fill */}
      <div className="flex-1" style={{ background }} />
      {/* Sidebar strip */}
      <div
        className="w-3.5"
        style={{
          background: sidebar,
          borderLeft: `1px solid ${border}`,
        }}
      />
      {/* Primary accent dot column */}
      <div
        className="flex w-3 flex-col items-center justify-center gap-0.5"
        style={{ background: sidebar }}
      >
        <span
          className="block h-1.5 w-1.5 rounded-full"
          style={{ background: primary }}
        />
        <span
          className="block h-1 w-1 rounded-full opacity-50"
          style={{ background: primary }}
        />
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Selector
// ─────────────────────────────────────────────────────────────────────────────

export function ThemeSelector() {
  const { themeId, themes, setTheme } = useAppTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {themes.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={[
              "flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent hover:text-accent-foreground",
            ].join(" ")}
            onClick={() => setTheme(theme.id)}
          >
            <ThemeSwatches themeId={theme.id} />

            <span className="flex min-w-0 flex-1 flex-col">
              <span className="text-sm font-medium text-foreground">{theme.label}</span>
              <span className="text-xs text-muted-foreground">{theme.description}</span>
            </span>

            {selected ? (
              <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

