/**
 * AppThemeProvider — applies named CSS-variable themes to the document root.
 *
 * Uses the same useSyncExternalStore pattern as hooks/useTheme.ts so the
 * selected theme is reactive across tabs and survives fast-refresh.
 *
 * The provider writes both:
 *   - CSS custom properties onto document.documentElement.style (highest
 *     specificity, overrides the class-based vars in index.css)
 *   - The Tailwind `.dark` class so that `dark:` utilities keep working
 *
 * It also keeps localStorage["t3code:theme"] in sync so the existing
 * useTheme hook never disagrees on the light/dark state.
 */

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import { BUILT_IN_THEMES, THEME_IDS, getThemeById, isValidThemeId } from "@t3tools/shared/theme";
import type { AppTheme, ThemeId } from "@t3tools/shared/theme";

// ─────────────────────────────────────────────────────────────────────────────
// Storage keys
// ─────────────────────────────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:app-theme";
/**
 * The legacy key owned by hooks/useTheme.ts. We keep it in sync so dark-mode
 * CSS-class logic in that hook continues to agree with the named theme choice.
 */
const LEGACY_DARK_KEY = "t3code:theme";

const DEFAULT_THEME_ID: ThemeId = "t3-dark";

// ─────────────────────────────────────────────────────────────────────────────
// External store (module-level, same pattern as hooks/useTheme.ts)
// ─────────────────────────────────────────────────────────────────────────────

let _listeners: Array<() => void> = [];

function emitChange(): void {
  for (const listener of _listeners) listener();
}

function getStoredThemeId(): ThemeId {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (isValidThemeId(raw)) return raw;
  } catch {
    // localStorage unavailable (SSR / privacy mode)
  }
  return DEFAULT_THEME_ID;
}

function applyThemeColors(themeId: ThemeId, suppressTransitions = false): void {
  const theme = getThemeById(themeId);
  const root = document.documentElement;
  const c = theme.colors;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Sync Tailwind dark-variant class
  root.classList.toggle("dark", c.isDark);

  // Keep legacy light/dark key in sync so hooks/useTheme.ts never disagrees
  try {
    localStorage.setItem(LEGACY_DARK_KEY, c.isDark ? "dark" : "light");
  } catch {
    // ignore
  }

  // Apply all color tokens as inline CSS custom properties.
  // Inline style has higher specificity than any class or :root rule, so these
  // will always override the defaults in index.css regardless of dark/light.
  root.style.setProperty("--background", c.background);
  root.style.setProperty("--foreground", c.foreground);
  root.style.setProperty("--card", c.card);
  root.style.setProperty("--card-foreground", c.cardForeground);
  root.style.setProperty("--popover", c.card);
  root.style.setProperty("--popover-foreground", c.cardForeground);
  root.style.setProperty("--primary", c.primary);
  root.style.setProperty("--primary-foreground", c.primaryForeground);
  root.style.setProperty("--secondary", c.accent);
  root.style.setProperty("--secondary-foreground", c.accentForeground);
  root.style.setProperty("--muted", c.muted);
  root.style.setProperty("--muted-foreground", c.mutedForeground);
  root.style.setProperty("--accent", c.accent);
  root.style.setProperty("--accent-foreground", c.accentForeground);
  root.style.setProperty("--border", c.border);
  root.style.setProperty("--input", c.input);
  root.style.setProperty("--ring", c.ring);

  // Theme-specific slots that don't map 1-to-1 to shadcn tokens
  root.style.setProperty("--theme-sidebar", c.sidebar);
  root.style.setProperty("--theme-sidebar-fg", c.sidebarForeground);
  root.style.setProperty("--theme-editor", c.editor);
  root.style.setProperty("--theme-editor-fg", c.editorForeground);
  root.style.setProperty("--theme-terminal", c.terminal);
  root.style.setProperty("--theme-terminal-fg", c.terminalForeground);
  root.style.setProperty("--theme-status-bar", c.statusBar);
  root.style.setProperty("--theme-status-bar-fg", c.statusBarForeground);

  if (suppressTransitions) {
    // Force a reflow before removing the class so the suppression takes effect
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately at module load to prevent a flash of unstyled content
applyThemeColors(getStoredThemeId());

function getSnapshot(): ThemeId {
  return getStoredThemeId();
}

function subscribe(listener: () => void): () => void {
  _listeners.push(listener);

  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyThemeColors(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    _listeners = _listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// React context
// ─────────────────────────────────────────────────────────────────────────────

interface AppThemeContextValue {
  /** The currently active theme ID. */
  themeId: ThemeId;
  /** The full AppTheme object for the active theme. */
  theme: AppTheme;
  /** All built-in themes in display order. */
  themes: readonly AppTheme[];
  /** Persist and apply a new named theme. */
  setTheme: (id: ThemeId) => void;
}

const AppThemeContext = createContext<AppThemeContextValue | null>(null);

// ─────────────────────────────────────────────────────────────────────────────
// Provider
// ─────────────────────────────────────────────────────────────────────────────

export function AppThemeProvider({ children }: { children: ReactNode }) {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);

  // Re-apply whenever the selected theme changes (handles hydration edge-cases)
  useEffect(() => {
    applyThemeColors(themeId);
  }, [themeId]);

  const setTheme = useCallback((id: ThemeId) => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // ignore
    }
    applyThemeColors(id, true);
    emitChange();
  }, []);

  const value: AppThemeContextValue = {
    themeId,
    theme: getThemeById(themeId),
    themes: THEME_IDS.map((id) => BUILT_IN_THEMES[id]) as readonly AppTheme[],
    setTheme,
  };

  return <AppThemeContext.Provider value={value}>{children}</AppThemeContext.Provider>;
}

// ─────────────────────────────────────────────────────────────────────────────
// Hook
// ─────────────────────────────────────────────────────────────────────────────

export function useAppTheme(): AppThemeContextValue {
  const ctx = useContext(AppThemeContext);
  if (!ctx) {
    throw new Error("useAppTheme must be used within an AppThemeProvider.");
  }
  return ctx;
}

